defmodule EcommerceAPI.ProductController do
  use Phoenix.Controller

  def index(conn, params) do
    search = params[:search]

    products = Ecto.Query
      |> from(p in Product, where fragment("name LIKE '%#{search}%'"))
      |> Repo.all()

    render conn, template: "products/index.html", products: products
  end
end